package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"io"
	"log"
	"os"
	"sort"
	"strings"

	"go.skia.org/infra/docker_experiment/go/config"
	"go.skia.org/infra/go/util"
	"go.skia.org/infra/task_scheduler/go/specs"
)

const (
	// STATIC indicates that an artifact is not generated by a task but
	// generated elsewhere and pinned to a specific sha256 in the config.
	STATIC = "<static>"
)

var (
	cfgFile       = flag.String("config", "", "Config file to validate.")
	imageManifest = flag.String("image-manifest", "", "Image manifest file to write.")
	tasksJson     = flag.String("tasks-json", "", "Add to the given tasks JSON file.")
)

func main() {
	flag.Parse()

	if *cfgFile == "" {
		flag.Usage()
		os.Exit(1)
	}

	// Parse the config file.
	var cfg *config.Config
	if err := util.WithReadFile(*cfgFile, func(r io.Reader) error {
		var err error
		cfg, err = config.Parse(r)
		return err
	}); err != nil {
		log.Fatal(err)
	}

	// Convert the config file to the Task Scheduler format.

	// Mapping of input name to the task which generates it.
	inputs := map[string]string{}
	for name := range cfg.Images {
		inputs[name] = STATIC
	}
	for name, task := range cfg.Tasks {
		if task.DockerBuild != nil {
			for _, output := range task.DockerBuild.Outputs {
				if exist, ok := inputs[output.Image]; ok {
					log.Fatalf("Only one task may generate %q; found %s and %s", output.Image, exist, name)
				}
				inputs[output.Image] = name
			}
		}
	}

	// The "output" TasksCfg.
	tasksCfg := &specs.TasksCfg{
		Tasks: map[string]*specs.TaskSpec{},
		Jobs:  map[string]*specs.JobSpec{},
	}
	for name, task := range cfg.Tasks {
		spec := &specs.TaskSpec{}

		// Only one type of task is allowed.
		found := false
		if task.DockerBuild != nil {
			found = true
			spec.Caches = []*specs.Cache{
				{
					Name: "docker",
					Path: "cache/docker",
				},
			}
			cmd := []string{
				"/usr/bin/docker", "run",
				"-v", "$(pwd):/src",
				"-v", "$(dirname ${LUCI_CONTEXT}):/AUTH",
				"-v", "/var/run/docker.sock:/var/run/docker.sock",
				"-v", "${ISOLATED_OUTDIR}:/out",
				"--env", "LUCI_CONTEXT=/AUTH/$(basename ${LUCI_CONTEXT})",
				"--env", "SWARMING_BOT_ID",
				"--env", "SWARMING_SERVER",
				"--env", "SWARMING_TASK_ID",
				"--network", "host",
				fmt.Sprintf("gcr.io/skia-public/canned-tasks@sha256:%s", cfg.Version),
				"/bin/docker-build",
				fmt.Sprintf("--project_id=%s", cfg.Project),
				fmt.Sprintf("--task_id=%s", specs.PLACEHOLDER_TASK_ID),
				fmt.Sprintf("--task_name=%s", specs.PLACEHOLDER_TASK_NAME),
				"--build-dir=/src",
				fmt.Sprintf("--build-file=/src/docker_experiment/%s", task.DockerBuild.File),
				fmt.Sprintf("--output-manifest=/out/manifest.%s", specs.PLACEHOLDER_TASK_NAME),
			}
			buildArgKeys := make([]string, 0, len(task.DockerBuild.BuildArgs))
			for k := range task.DockerBuild.BuildArgs {
				buildArgKeys = append(buildArgKeys, k)
			}
			sort.Strings(buildArgKeys)
			for _, k := range buildArgKeys {
				cmd = append(cmd, "--build-arg", fmt.Sprintf("%s=%s", k, task.DockerBuild.BuildArgs[k]))
			}
			baseImage := task.DockerBuild.Base
			if static, ok := cfg.Images[baseImage]; ok {
				baseImage = fmt.Sprintf("%s@sha256:%s", static.Name, static.Sha256)
			} else {
				dep := inputs[baseImage]
				cmd = append(cmd, "--input-manifest", fmt.Sprintf("/src/manifest.%s", dep))
				spec.Dependencies = append(spec.Dependencies, dep)
			}
			cmd = append(cmd, "--base", baseImage)
			for _, input := range task.DockerBuild.Inputs {
				image := input.Image
				if static, ok := cfg.Images[input.Image]; ok {
					image = fmt.Sprintf("%s@sha256:%s", static.Name, static.Sha256)
				} else {
					dep := inputs[input.Image]
					cmd = append(cmd, "--input-manifest", fmt.Sprintf("/src/manifest.%s", dep))
					spec.Dependencies = append(spec.Dependencies, dep)
				}
				cmd = append(cmd, "--input", fmt.Sprintf("%s:%s:%s", image, input.Source, input.Dest))
			}
			for _, output := range task.DockerBuild.Outputs {
				o := output.Image
				if o == "" {
					log.Fatal("Task output must have an 'image' key.")
				}
				if output.Target != "" {
					o = fmt.Sprintf("%s=%s", output.Target, output.Image)
				}
				cmd = append(cmd, "--output", o)
			}
			spec.Command = []string{"/bin/bash", "-c", strings.Join(cmd, " ")}
			spec.ServiceAccount = "skia-external-compile-tasks@skia-swarming-bots.iam.gserviceaccount.com"
		} else if task.DockerRun != nil {
			if found {
				log.Fatalf("Only one definition allowed per task! %s", name)
			}
			found = true
			cmd := []string{
				"/usr/bin/docker", "run",
				"-v", "$(pwd):/src",
				"-v", "$(dirname ${LUCI_CONTEXT}):/auth",
				"-v", "/var/run/docker.sock:/var/run/docker.sock",
				"-v", "${ISOLATED_OUTDIR}:/out",
				"--env", "LUCI_CONTEXT=/auth/$(basename ${LUCI_CONTEXT})",
				"--env", "SWARMING_BOT_ID",
				"--env", "SWARMING_SERVER",
				"--env", "SWARMING_TASK_ID",
				"--network", "host",
				fmt.Sprintf("gcr.io/skia-public/canned-tasks@sha256:%s", cfg.Version),
				"/bin/docker-run",
				fmt.Sprintf("--project_id=%s", cfg.Project),
				fmt.Sprintf("--task_id=%s", specs.PLACEHOLDER_TASK_ID),
				fmt.Sprintf("--task_name=%s", specs.PLACEHOLDER_TASK_NAME),
				"--input-manifest", "/src/docker_experiment/manifest.static",
				"--auth-dir=$(dirname ${LUCI_CONTEXT})",
				"--mount-dir=$(pwd)/mnt:/src/mnt",
			}
			image := task.DockerRun.Image
			if static, ok := cfg.Images[image]; ok {
				image = fmt.Sprintf("%s@sha256:%s", static.Name, static.Sha256)
			} else {
				dep := inputs[image]
				cmd = append(cmd, "--input-manifest", fmt.Sprintf("/src/manifest.%s", dep))
				spec.Dependencies = append(spec.Dependencies, dep)
			}
			for _, v := range task.DockerRun.Environment {
				cmd = append(cmd, "--env", v)
			}
			cmd = append(cmd, fmt.Sprintf("--image=%s", image))
			for _, input := range task.DockerRun.DockerRunInputs {
				image := input.Image
				if static, ok := cfg.Images[input.Image]; ok {
					image = fmt.Sprintf("%s@sha256:%s", static.Name, static.Sha256)
				} else {
					dep := inputs[input.Image]
					cmd = append(cmd, "--input-manifest", fmt.Sprintf("/src/manifest.%s", dep))
					spec.Dependencies = append(spec.Dependencies, dep)
				}
				cmd = append(cmd, "--input", fmt.Sprintf("%s:%s:%s", image, input.Source, input.Mount))
			}
			cmd = append(cmd, task.DockerRun.Command...)
			spec.Command = []string{"/bin/bash", "-c", strings.Join(cmd, " ")}
			spec.ServiceAccount = "skia-external-compile-tasks@skia-swarming-bots.iam.gserviceaccount.com"
		} else if task.RawCmd != nil {
			if found {
				log.Fatalf("Only one definition allowed per task! %s", name)
			}
			found = true
			spec.Command = task.RawCmd.Command
		}
		if !found {
			log.Fatalf("No task definition for %s", name)
		}
		sort.Strings(spec.Dependencies)

		// Isolate file. This should go away at some point.
		spec.Isolate = "docker_experiment.isolate"

		// Dimensions.
		for k, v := range task.Dimensions {
			spec.Dimensions = append(spec.Dimensions, fmt.Sprintf("%s:%s", k, v))
		}
		sort.Strings(spec.Dimensions)

		tasksCfg.Tasks[name] = spec
	}

	for name, job := range cfg.Jobs {
		spec := &specs.JobSpec{}
		spec.TaskSpecs = job.Tasks
		if job.Trigger != "commit" {
			spec.Trigger = job.Trigger
		}
		tasksCfg.Jobs[name] = spec
	}

	if err := tasksCfg.Validate(); err != nil {
		log.Fatal(err)
	}

	if *imageManifest != "" {
		if err := util.WithWriteFile(*imageManifest, func(w io.Writer) error {
			lines := make([]string, 0, len(cfg.Images))
			for _, img := range cfg.Images {
				lines = append(lines, fmt.Sprintf("%s@sha256:%s", img.Name, img.Sha256))
			}
			sort.Strings(lines)
			_, err := w.Write([]byte(strings.Join(lines, "\n")))
			return err
		}); err != nil {
			log.Fatal(err)
		}
	}
	if *tasksJson != "" {
		var addToCfg specs.TasksCfg
		if err := util.WithReadFile(*tasksJson, func(r io.Reader) error {
			return json.NewDecoder(r).Decode(&addToCfg)
		}); err != nil {
			log.Fatal(err)
		}
		for name, task := range tasksCfg.Tasks {
			addToCfg.Tasks[name] = task
		}
		for name, job := range tasksCfg.Jobs {
			addToCfg.Jobs[name] = job
		}
		if err := util.WithWriteFile(*tasksJson, func(w io.Writer) error {
			b, err := specs.EncodeTasksCfg(&addToCfg)
			if err != nil {
				return err
			}
			_, err = w.Write(b)
			return err
		}); err != nil {
			log.Fatal(err)
		}
	}
}
